namespace QBEngineer.Api.Data.TrainingContent;

public class LeadsTraining : TrainingContentBase
{
    public LeadsTraining(AppDbContext db, Dictionary<string, int> slugMap) : base(db, slugMap) { }

    public override async Task SeedAsync()
    {
        // ── Overview (Article) ───────────────────────────────────────────
        await GetOrCreateModule(new TrainingModule
        {
            Title = "Leads Overview",
            Slug = "leads-overview",
            Summary = "What leads are, how the sales pipeline works, lead statuses, converting leads to customers, and how leads connect to quotes and jobs.",
            ContentType = TrainingContentType.Article,
            EstimatedMinutes = 4,
            IsPublished = true,
            SortOrder = 1,
            AppRoutes = """["/leads"]""",
            Tags = """["leads","sales"]""",
            ContentJson = """{"body":"## Leads Overview\n\nThe Leads module is your sales pipeline. It tracks potential customers from first contact through qualification and quoting to conversion or loss. Every lead represents a company that might become a customer — and every customer relationship starts here.\n\n### What Is a Lead?\n\nA lead is a prospective customer record. It captures the company name, contact person, email, phone, how they found you (source), and any notes about the opportunity. Leads move through a defined pipeline of statuses as you work them.\n\n### The Sales Pipeline\n\nLeads progress through five statuses:\n\n1. **New** — A fresh lead that hasn't been contacted yet. This is the default status when you create a lead.\n2. **Contacted** — You've reached out to the prospect. They know who you are and what you offer.\n3. **Quoting** — The prospect has expressed interest and you're preparing or have sent a quote/estimate.\n4. **Converted** — The lead became a customer. A Customer record is created automatically when you convert.\n5. **Lost** — The opportunity didn't work out. You can record a reason (competitor won, budget, timing, etc.) for future analysis.\n\nLeads can move forward or backward through New, Contacted, and Quoting freely. Converted and Lost are terminal states, though a Lost lead can be reopened back to New.\n\n### Two Ways to View Your Pipeline\n\nThe Leads page offers two view modes:\n\n- **Table View** — A sortable, filterable data table showing all leads with columns for company, contact, source, status, follow-up date, and created date. Best for searching and bulk review.\n- **Pipeline View** — A kanban-style board with columns for each status. Drag and drop cards between columns to update status. Best for visual pipeline management.\n\nSwitch between views using the toggle buttons in the page header. Your preference is saved.\n\n### Follow-Up Dates\n\nEach lead can have a follow-up date. When the follow-up date passes without the lead being updated, the date displays in red (overdue) as a visual reminder. Use follow-up dates to ensure no lead falls through the cracks.\n\n### Lead Sources\n\nThe Source field tracks how leads find you — referral, website, trade show, cold call, etc. Sources are configured in Admin → Reference Data (group: lead_source), so your team can add new sources without code changes. Tracking sources helps you understand which marketing channels produce results.\n\n### Converting Leads to Customers\n\nWhen a lead is ready to become a customer, you have two conversion options:\n\n- **Convert to Customer** — Creates a Customer record from the lead's company name, contact, email, and phone. The lead status changes to Converted.\n- **Convert to Customer + Create Job** — Same as above, plus creates a new Job on the default kanban board linked to the new customer. Use this when you're ready to start work immediately.\n\nConversion is a one-way action. Once converted, the lead shows a green confirmation badge and links to the customer record. You cannot convert a Lost lead — reopen it first.\n\n### How Leads Connect to Quotes and Jobs\n\nThe typical flow is: Lead → Customer → Quote/Estimate → Sales Order → Job. Converting a lead creates the Customer record. From there, you can create Estimates (ballpark figures) or Quotes (binding, line-itemized) for that customer. When a quote is accepted, it converts to a Sales Order, which can generate Jobs on the kanban board.\n\n### Marking a Lead as Lost\n\nWhen you mark a lead as Lost (either by clicking the Lost status button or dragging the card to the Lost column in pipeline view), a dialog appears asking for the reason. The lost reason is optional but valuable — it helps you identify patterns (price too high, competitor won, bad timing) and improve your win rate over time.\n\n### Reopening Lost Leads\n\nCircumstances change. A Lost lead can be reopened by clicking the 'Reopen Lead' button in the detail view. This resets the status to New so you can work the opportunity again.","sections":[]}"""
        });

        // ── Walkthrough ──────────────────────────────────────────────────
        await GetOrCreateModule(new TrainingModule
        {
            Title = "Leads — Guided Tour",
            Slug = "leads-walkthrough",
            Summary = "A guided tour of the leads list page: search, filters, view modes, creating leads, pipeline drag-and-drop, and viewing lead details.",
            ContentType = TrainingContentType.Walkthrough,
            EstimatedMinutes = 5,
            IsPublished = true,
            SortOrder = 2,
            AppRoutes = """["/leads"]""",
            Tags = """["leads","sales","walkthrough"]""",
            ContentJson = """{"appRoute":"/leads","startButtonLabel":"Tour Leads","steps":[{"element":"[data-testid='new-lead-btn']","popover":{"title":"Add Lead Button","description":"Click here to create a new lead. You'll enter the company name, contact name, email, phone, source, follow-up date, and notes. Company Name is the only required field.","side":"bottom"}},{"element":".view-toggle","popover":{"title":"View Mode Toggle","description":"Switch between Table View (sortable data table) and Pipeline View (kanban-style drag-and-drop board). Your preference is saved to localStorage and persists across sessions.","side":"bottom"}},{"element":".filters-bar app-input","popover":{"title":"Search Leads","description":"Search by company name or contact name. Type your search term and press Enter to filter. Results update in the table below. The pipeline view also filters as you type.","side":"bottom"}},{"element":".filters-bar app-select","popover":{"title":"Status Filter","description":"Filter leads by status: New, Contacted, Quoting, Converted, or Lost. Select 'All Statuses' to see everything. In pipeline view, only the search box is shown since columns already represent statuses.","side":"bottom"}},{"element":"app-data-table","popover":{"title":"Leads Table","description":"Click any row to open the lead detail dialog. Columns include Company, Contact, Source, Status (color-coded chip), Follow-Up Date (red when overdue), and Created date. Click column headers to sort. Use the gear icon to manage column visibility and order.","side":"top"}}]}"""
        });

