            Title = "Leads Field Reference",
            Slug = "leads-field-reference",
            Summary = "Complete reference for every field, button, status, validation rule, and action in the Leads module.",
            ContentType = TrainingContentType.QuickRef,
            EstimatedMinutes = 4,
            IsPublished = true,
            SortOrder = 3,
            AppRoutes = """["/leads"]""",
            Tags = """["leads","sales","reference"]""",
            ContentJson = """{"title":"Leads Field Reference","groups":[{"heading":"Lead Form Fields","items":[{"label":"Company Name (required)","value":"Text input, identifies the prospect company. Must not be empty. This becomes the Customer name if the lead is converted. data-testid: lead-company-name"},{"label":"Contact Name","value":"Text input, optional. The person at the company you're working with. If provided, a Contact record is created when the lead is converted (first/last name split on space). data-testid: lead-contact-name"},{"label":"Email","value":"Text input, optional. Validated as email format (must contain @). Carried over to the Customer and Contact records on conversion. data-testid: lead-email"},{"label":"Phone","value":"Text input, optional. Phone number for the contact. Carried over to Customer and Contact on conversion. data-testid: lead-phone"},{"label":"Source","value":"Dropdown, optional. How the lead found you. Options are loaded from Reference Data (group: lead_source) — configurable in Admin. Examples: Referral, Website, Trade Show, Cold Call. Includes a '-- None --' option. data-testid: lead-source"},{"label":"Follow-Up Date","value":"Date picker, optional. When you should next follow up with this lead. Displays in red (overdue) in the table and detail view when the date has passed. data-testid: lead-follow-up"},{"label":"Notes","value":"Textarea, optional. Free-form notes about the lead, opportunity details, conversation history, or requirements. data-testid: lead-notes"}]},{"heading":"Lead Statuses","items":[{"label":"New (primary/blue chip)","value":"Default status for new leads. Indicates the lead has not been contacted yet. CSS class: chip--primary."},{"label":"Contacted (info/teal chip)","value":"You have reached out to the prospect. They are aware of your company and offerings. CSS class: chip--info."},{"label":"Quoting (warning/yellow chip)","value":"A quote or estimate is being prepared or has been sent to the prospect. CSS class: chip--warning."},{"label":"Converted (success/green chip)","value":"Terminal status. The lead has been converted to a Customer record. A green check badge appears in the detail view. Cannot be set manually — only through the Convert action. CSS class: chip--success."},{"label":"Lost (muted/gray chip)","value":"Terminal status. The opportunity did not result in a customer. A lost reason can be recorded. Can be reopened back to New. CSS class: chip--muted."}]},{"heading":"Table Columns","items":[{"label":"Company","value":"Sortable. The company name, displayed in bold/emphasized text."},{"label":"Contact","value":"Sortable. Contact person name. Shows em-dash (—) when empty."},{"label":"Source","value":"Sortable. Lead source from Reference Data. Shows em-dash (—) when empty."},{"label":"Status","value":"Sortable, filterable (enum filter). Color-coded chip: New (blue), Contacted (teal), Quoting (yellow), Converted (green), Lost (gray)."},{"label":"Follow-Up","value":"Sortable, date type. Shows the follow-up date in MM/dd/yyyy format. Displays in red when overdue. Shows em-dash (—) when not set."},{"label":"Created","value":"Sortable, date type. Date the lead was created, in MM/dd/yyyy format."}]},{"heading":"Buttons and Actions","items":[{"label":"New Lead (primary button, header)","value":"Opens the create lead dialog. data-testid: new-lead-btn"},{"label":"Table View toggle (icon button)","value":"Switches to sortable data table view. Icon: view_list. Persisted to localStorage."},{"label":"Pipeline View toggle (icon button)","value":"Switches to kanban-style pipeline board. Icon: view_column. Persisted to localStorage."},{"label":"Save / Create Lead (dialog footer)","value":"Creates or updates the lead. Disabled when form is invalid or save is in progress. Shows validation popover on hover when disabled. data-testid: lead-save-btn"},{"label":"Cancel (dialog footer)","value":"Closes the dialog without saving."},{"label":"Edit (detail dialog icon button)","value":"Opens the edit dialog pre-filled with the lead's current values. Icon: edit."},{"label":"Close (detail dialog icon button)","value":"Closes the detail dialog. Icon: close."},{"label":"Status buttons (detail panel)","value":"Quick-action buttons to change status to New, Contacted, Quoting, or Lost directly from the detail panel. Hidden when lead is Converted or Lost. data-testid: lead-status-btn-{status}"},{"label":"Convert to Customer (detail panel)","value":"Creates a Customer record from the lead data. Shows confirmation dialog first. Only available when status is not Converted or Lost. data-testid: lead-convert-btn"},{"label":"Convert + Create Job (detail panel)","value":"Converts to Customer and creates a Job on the default kanban board. Only available when status is not Converted or Lost. Icon: work."},{"label":"Reopen Lead (detail panel)","value":"Resets a Lost lead back to New status. Only visible when status is Lost. Icon: replay."},{"label":"Confirm Lost (lost reason dialog)","value":"Confirms marking the lead as Lost with the optional reason."},{"label":"Row click","value":"Opens the lead detail dialog showing all fields, status actions, convert options, and activity log."},{"label":"Pipeline card drag","value":"Drag a card between pipeline columns to change status. Dropping on Lost opens the lost reason dialog."}]},{"heading":"Validation Rules","items":[{"label":"Company Name","value":"Required. Cannot be empty."},{"label":"Email","value":"Optional, but must be valid email format if provided (Validators.email)."},{"label":"All other fields","value":"Optional. No additional format restrictions."},{"label":"Submit button popover","value":"When form is invalid, hovering over Save shows a validation popover listing which fields need attention (e.g., 'Company Name is required')."},{"label":"Conversion guard","value":"Cannot convert a lead that is already Converted or Lost (server returns 400/InvalidOperationException). Lost leads must be reopened first."}]},{"heading":"Detail Dialog Sections","items":[{"label":"Header","value":"Company name (bold), contact name (subtitle), edit and close icon buttons."},{"label":"Info Grid","value":"Status chip, email, phone, source, follow-up date (red if overdue), lost reason (if Lost). Empty fields are hidden."},{"label":"Notes Section","value":"Displays lead notes as a paragraph. Hidden when notes are empty."},{"label":"Status Actions","value":"Row of status buttons for quick status changes. Hidden when Converted or Lost."},{"label":"Convert Actions","value":"Convert to Customer and Convert + Create Job buttons. Hidden when Converted or Lost."},{"label":"Converted Info","value":"Green check badge with confirmation text. Only shown when status is Converted."},{"label":"Reopen Action","value":"Reopen Lead button. Only shown when status is Lost."},{"label":"Activity Timeline","value":"Chronological activity log for the lead (EntityActivitySectionComponent). Shows status changes, edits, notes, and conversion events."}]},{"heading":"Pipeline View Details","items":[{"label":"Columns","value":"Five columns: New, Contacted, Quoting, Converted, Lost. Converted and Lost columns have muted styling."},{"label":"Column header","value":"Status name + count badge (chip--muted)."},{"label":"Card content","value":"Company name (bold), contact name with avatar initials, source with label icon, follow-up date with event icon (red if overdue)."},{"label":"Empty column","value":"Shows inbox icon with 'No leads' text."},{"label":"Drag-and-drop","value":"CDK drag-drop. Cards can be dragged between any columns. Dropping on Lost triggers the lost reason dialog. Connected drop lists allow cross-column movement."}]}]}"""
        });

        // ── Knowledge Check (Quiz) ───────────────────────────────────────
        await GetOrCreateModule(new TrainingModule
        {
            Title = "Leads Knowledge Check",
            Slug = "leads-quiz",
            Summary = "Test your knowledge of the Leads module: statuses, conversion, pipeline management, and common workflows.",
            ContentType = TrainingContentType.Quiz,
            EstimatedMinutes = 5,
            IsPublished = true,
            SortOrder = 4,
            AppRoutes = """["/leads"]""",
            Tags = """["leads","sales","quiz"]""",
            ContentJson = """{"passingScore":80,"questionsPerQuiz":8,"shuffleOptions":true,"showExplanationsAfterSubmit":true,"questions":[{"id":"ld1","text":"A potential customer called asking about your machining services. What is the first step to track this opportunity in QB Engineer?","options":[{"id":"a","text":"Create a Customer record in the Customers module"},{"id":"b","text":"Navigate to Leads, click New Lead, and enter the company name, contact info, and source","isCorrect":true},{"id":"c","text":"Create a Quote in the Quotes module with their company name"},{"id":"d","text":"Add a Job to the Kanban Board tagged as a prospect"}],"explanation":"New sales opportunities start as Leads. Click New Lead, fill in the company name (required), contact name, email, phone, and source. The lead starts in New status. Don't create a Customer record until the lead is qualified and ready for conversion."},{"id":"ld2","text":"You've sent an email introduction to a new lead. What status should the lead be in now?","options":[{"id":"a","text":"New — the lead hasn't responded yet"},{"id":"b","text":"Contacted — you've reached out to the prospect","isCorrect":true},{"id":"c","text":"Quoting — any communication counts as quoting"},{"id":"d","text":"Converted — the lead knows about your company now"}],"explanation":"Contacted means you've reached out to the prospect. They are aware of your company. Move to Quoting only when you're actually preparing or have sent a price quote or estimate."},{"id":"ld3","text":"What is the difference between the Quoting and Converted lead statuses?","options":[{"id":"a","text":"Quoting means a quote was sent; Converted means the quote was accepted"},{"id":"b","text":"Quoting means you're preparing or have sent a quote; Converted means the lead has been turned into a Customer record","isCorrect":true},{"id":"c","text":"They are the same — Converted is just the final stage of Quoting"},{"id":"d","text":"Quoting is for estimates only; Converted is for formal quotes"}],"explanation":"Quoting indicates a quote or estimate is in progress. Converted is a terminal status that means the lead has been turned into a Customer record via the Convert action. These are distinct pipeline stages."},{"id":"ld4","text":"You want to convert a lead to a customer and immediately start a production job. Which action do you use?","options":[{"id":"a","text":"Convert to Customer, then manually create a Job on the Kanban Board"},{"id":"b","text":"Convert to Customer + Create Job — it creates both in one step","isCorrect":true},{"id":"c","text":"Create the Job first, then convert the lead and link them"},{"id":"d","text":"You cannot create a job from a lead — jobs are created from Sales Orders only"}],"explanation":"The 'Convert to Customer + Create Job' button creates a Customer record from the lead data AND creates a new Job on the default kanban board linked to that customer — all in one action."},{"id":"ld5","text":"A lead's follow-up date is showing in red in the table. What does this mean?","options":[{"id":"a","text":"The lead is marked as high priority"},{"id":"b","text":"The follow-up date has passed and the lead hasn't been updated — it's overdue","isCorrect":true},{"id":"c","text":"The lead is about to be automatically archived"},{"id":"d","text":"Someone else is currently working on this lead"}],"explanation":"A red follow-up date means the date has passed (overdue). This is a visual reminder that you need to follow up with the prospect. The lead won't be automatically changed — it's just a visual indicator."},{"id":"ld6","text":"You lost a deal to a competitor. How do you record this in QB Engineer?","options":[{"id":"a","text":"Delete the lead from the system"},{"id":"b","text":"Change the status to Lost — a dialog appears where you can enter the reason (e.g., 'Competitor won on price')","isCorrect":true},{"id":"c","text":"Archive the lead by clicking the archive button"},{"id":"d","text":"Move the lead to the Converted column and add a note saying it was lost"}],"explanation":"Click the Lost status button or drag the card to the Lost column. A dialog appears asking for the lost reason (optional but recommended). The reason is stored for analysis. Lost leads can be reopened later if circumstances change."},{"id":"ld7","text":"A lead you marked as Lost six months ago has come back with renewed interest. What do you do?","options":[{"id":"a","text":"Create a new lead — lost leads cannot be reused"},{"id":"b","text":"Open the lead detail, click the Reopen Lead button to reset it to New status","isCorrect":true},{"id":"c","text":"Change the status directly to Contacted by editing the lead"},{"id":"d","text":"Convert the lost lead directly to a customer"}],"explanation":"Lost leads can be reopened. In the detail view, click the 'Reopen Lead' button (replay icon). This resets the status to New so you can work the opportunity again. You cannot convert a Lost lead directly — you must reopen it first."},{"id":"ld8","text":"In Pipeline View, you drag a lead card from the Contacted column to the Lost column. What happens?","options":[{"id":"a","text":"The status changes to Lost immediately with no further action"},{"id":"b","text":"The card moves optimistically, and a dialog appears asking for the lost reason","isCorrect":true},{"id":"c","text":"The drag is rejected — you can only mark leads as Lost from the detail panel"},{"id":"d","text":"The lead is permanently deleted from the system"}],"explanation":"Dragging a card to the Lost column triggers the lost reason dialog. The card moves optimistically (appears in the Lost column immediately), but you can enter a reason for losing the deal. The reason is optional — you can confirm without entering one."},{"id":"ld9","text":"Where do the options in the Source dropdown come from?","options":[{"id":"a","text":"They are hardcoded in the application and cannot be changed"},{"id":"b","text":"They come from Reference Data in Admin settings (group: lead_source) and can be configured by admins","isCorrect":true},{"id":"c","text":"Each user creates their own source list in their profile settings"},{"id":"d","text":"They are imported from your email client automatically"}],"explanation":"Lead sources are managed in Admin → Reference Data under the lead_source group. Admins can add, rename, or remove sources without code changes. This ensures consistent tracking across the team."},{"id":"ld10","text":"When you convert a lead that has a Contact Name of 'Jane Smith', what happens to that contact information?","options":[{"id":"a","text":"Only the company name is used — contact details must be re-entered on the Customer record"},{"id":"b","text":"A Contact record is created on the new Customer with first name 'Jane', last name 'Smith', marked as primary, with the lead's email and phone","isCorrect":true},{"id":"c","text":"The contact name is stored in the Customer's notes field"},{"id":"d","text":"A separate user account is created for Jane Smith"}],"explanation":"When converting a lead with a contact name, the system creates a Contact record on the new Customer. The name is split on the first space (first: 'Jane', last: 'Smith'). The contact gets the lead's email and phone, and is marked as the primary contact."},{"id":"ld11","text":"You want to see only leads that are in the Quoting stage. What is the fastest way?","options":[{"id":"a","text":"Switch to Pipeline View — the Quoting column shows exactly those leads","isCorrect":true},{"id":"b","text":"Export all leads to a spreadsheet and filter there"},{"id":"c","text":"Use the search box to type 'Quoting'"},{"id":"d","text":"Go to Reports and run a leads-by-status report"}],"explanation":"The Pipeline View organizes leads by status columns, so the Quoting column shows exactly what you need at a glance. Alternatively, in Table View you can use the Status filter dropdown to select Quoting. Both work, but Pipeline View gives you the visual overview."},{"id":"ld12","text":"What validation must pass before you can save a new lead?","options":[{"id":"a","text":"Company Name, Contact Name, and Email are all required"},{"id":"b","text":"Only Company Name is required — all other fields are optional","isCorrect":true},{"id":"c","text":"Company Name and Source are required"},{"id":"d","text":"All fields are optional — you can save a completely blank lead"}],"explanation":"Company Name is the only required field. Contact Name, Email, Phone, Source, Follow-Up Date, and Notes are all optional. If Email is provided, it must be in valid email format (contains @). When the form is invalid, hovering over the Save button shows a validation popover listing which fields need attention."}]}"""
        });

        Log.Information("Seeded Leads training modules");
    }
}
